56: func readQuotaConfig(cfg *setting.Cfg) (*quota.Map, error) {
57: 	limits := &quota.Map{}
58: 
59: 	if cfg == nil {
60: 		return limits, nil
61: 	}
62: 
63: 	globalQuotaTag, err := quota.NewTag(apikey.QuotaTargetSrv, apikey.QuotaTarget, quota.GlobalScope)
64: 	if err != nil {
65: 		return limits, err
66: 	}
67: 	orgQuotaTag, err := quota.NewTag(apikey.QuotaTargetSrv, apikey.QuotaTarget, quota.OrgScope)
68: 	if err != nil {
69: 		return limits, err
70: 	}
71: 
72: 	limits.Set(globalQuotaTag, cfg.Quota.Global.ApiKey)
73: 	limits.Set(orgQuotaTag, cfg.Quota.Org.ApiKey)
74: 	return limits, nil
75: }
