126: func CanAdminPlugins(cfg *setting.Cfg, accessControl ac.AccessControl) func(c *contextmodel.ReqContext) {
127: 	return func(c *contextmodel.ReqContext) {
128: 		hasAccess := ac.HasAccess(accessControl, c)
129: 		if !pluginaccesscontrol.ReqCanAdminPlugins(cfg)(c) && !hasAccess(pluginaccesscontrol.AdminAccessEvaluator) {
130: 			accessForbidden(c)
131: 			return
132: 		}
133: 		if c.AllowAnonymous && !c.IsSignedIn && shouldForceLogin(c) {
134: 			notAuthorized(c)
135: 			return
136: 		}
137: 	}
138: }
